13→pub async fn spawn_app() -> TestApp {
14→    let mut settings = get_configuration().expect("Failed to read configuration");
15→
16→    // Use a random database name for test isolation
17→    settings.database.database_name = Uuid::new_v4().to_string();
18→
19→    // Use port 0 to get a random available port
20→    settings.application.port = 0;
21→
22→    // Create the test database
23→    configure_database(&settings.database).await;
24→
25→    let app = Application::build(&settings)
26→        .await
27→        .expect("Failed to build application");
28→
29→    let address = format!("http://127.0.0.1:{}", app.port());
30→    let pool = PgPool::connect_with(settings.database.connect_options())
31→        .await
32→        .expect("Failed to connect to database");
33→
34→    tokio::spawn(app.run());
35→
