43→async fn configure_database(settings: &DatabaseSettings) {
44→    // Connect to the default postgres database to create our test database
45→    let mut connection = PgConnection::connect_with(&settings.connect_options_without_db())
46→        .await
47→        .expect("Failed to connect to Postgres");
48→
49→    connection
50→        .execute(format!(r#"CREATE DATABASE "{}";"#, settings.database_name).as_str())
51→        .await
52→        .expect("Failed to create database");
53→}
