    pool: &PgPool,
    item_id: &InboxItemId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM inbox_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

