 2→use sqlx::postgres::PgPoolOptions;
 3→use sqlx::PgPool;
 4→use tokio::net::TcpListener;
 5→use tower_http::request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer};
 6→use tower_http::services::ServeDir;
 7→use tower_http::trace::TraceLayer;
 8→use tower_sessions::SessionManagerLayer;
 9→use tower_sessions_sqlx_store::PostgresStore;
10→
11→use crate::configuration::Settings;
12→use crate::routes::{
13→    get_dashboard, get_edit_todo, get_forgot_password, get_inbox, get_login, get_next_actions,
14→    get_projects, get_register, get_review, get_someday_maybe, get_todo_item, get_todos_page,
15→    get_waiting_for, health_check, index, post_delete_todo, post_edit_todo, post_login,
16→    post_logout, post_register, post_todo, post_toggle_todo,
17→};
18→
19→pub struct Application {
20→    listener: TcpListener,
21→    pool: PgPool,
22→}
23→
24→impl Application {
25→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
26→        let pool = PgPoolOptions::new()
27→            .max_connections(5)
28→            .connect_with(settings.database.connect_options())
29→            .await?;
30→
31→        sqlx::migrate!("./migrations").run(&pool).await?;
32→
33→        let session_store = PostgresStore::new(pool.clone());
34→        session_store.migrate().await?;
35→
36→        let address = format!(
37→            "{}:{}",
38→            settings.application.host, settings.application.port
39→        );
40→        let listener = TcpListener::bind(&address).await?;
41→
42→        tracing::info!("Listening on {}", listener.local_addr()?);
43→
44→        Ok(Self { listener, pool })
45→    }
46→
47→    pub fn port(&self) -> u16 {
48→        self.listener.local_addr().unwrap().port()
49→    }
50→
51→    pub fn router(pool: PgPool) -> Router {
52→        let x_request_id = axum::http::HeaderName::from_static("x-request-id");
53→
54→        let session_store = PostgresStore::new(pool.clone());
55→        let session_layer = SessionManagerLayer::new(session_store);
56→
57→        Router::new()
58→            .route("/", axum::routing::get(index))
59→            .route("/dashboard", axum::routing::get(get_dashboard))
60→            .route("/inbox", axum::routing::get(get_inbox))
61→            .route("/next-actions", axum::routing::get(get_next_actions))
62→            .route("/projects", axum::routing::get(get_projects))
63→            .route("/waiting-for", axum::routing::get(get_waiting_for))
64→            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
65→            .route("/review", axum::routing::get(get_review))
66→            .route(
67→                "/register",
68→                axum::routing::get(get_register).post(post_register),
