  1→use askama::Template;
  2→use axum::extract::{Path, State};
  3→use axum::http::{HeaderMap, StatusCode};
  4→use axum::response::{Html, IntoResponse, Redirect, Response};
  5→use axum::Form;
  6→use sqlx::PgPool;
  7→use uuid::Uuid;
  8→
  9→use super::auth::AuthenticatedUser;
 10→use crate::domain::{InboxItem, InboxItemId};
 11→use crate::services::inbox_service::{
 12→    capture_inbox_item, delete_inbox_item, get_inbox_items, CaptureInboxError, DeleteInboxError,
 13→};
 14→
 15→fn is_htmx_request(headers: &HeaderMap) -> bool {
 16→    headers.contains_key("hx-request")
 17→}
 18→
 19→fn htmx_response_with_announce(body: Html<String>, message: &str) -> Response {
 20→    let trigger_json = format!(r#"{{"announce":"{}"}}"#, message);
 21→    (
 22→        [(
 23→            axum::http::header::HeaderName::from_static("hx-trigger"),
 24→            axum::http::HeaderValue::from_str(&trigger_json).unwrap(),
 25→        )],
 26→        body,
 27→    )
 28→        .into_response()
 29→}
 30→
 31→pub struct InboxItemView {
 32→    pub id: String,
 33→    pub title: String,
 34→}
 35→
 36→impl From<&InboxItem> for InboxItemView {
 37→    fn from(item: &InboxItem) -> Self {
 38→        Self {
 39→            id: item.id().as_uuid().to_string(),
 40→            title: item.title().as_str().to_string(),
 41→        }
 42→    }
 43→}
 44→
 45→#[derive(Template)]
 46→#[template(path = "inbox.html")]
 47→struct InboxTemplate {
 48→    current_page: &'static str,
 49→    inbox_count: i64,
 50→    items: Vec<InboxItemView>,
 51→}
 52→
 53→#[derive(Template)]
 54→#[template(path = "inbox_item.html")]
 55→struct InboxItemTemplate {
 56→    item: InboxItemView,
 57→}
 58→
 59→pub async fn get_inbox(
 60→    AuthenticatedUser(user_id): AuthenticatedUser,
 61→    State(pool): State<PgPool>,
 62→) -> Result<impl IntoResponse, InboxError> {
 63→    let items = get_inbox_items(&pool, &user_id)
 64→        .await
 65→        .map_err(InboxError::Unexpected)?;
 66→
 67→    let inbox_count = items.len() as i64;
 68→    let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();
 69→
 70→    let template = InboxTemplate {
 71→        current_page: "inbox",
 72→        inbox_count,
 73→        items: item_views,
 74→    };
 75→    Ok(Html(template.render()?))
 76→}
 77→
 78→#[derive(serde::Deserialize)]
 79→pub struct CaptureForm {
 80→    pub title: String,
 81→}
 82→
 83→pub async fn post_inbox(
 84→    AuthenticatedUser(user_id): AuthenticatedUser,
 85→    State(pool): State<PgPool>,
 86→    headers: HeaderMap,
 87→    Form(form): Form<CaptureForm>,
 88→) -> Result<Response, InboxError> {
 89→    let htmx = is_htmx_request(&headers);
 90→
 91→    // Silently ignore empty/whitespace-only submissions
 92→    if form.title.trim().is_empty() {
 93→        if htmx {
 94→            return Ok(StatusCode::NO_CONTENT.into_response());
 95→        }
 96→        return Ok(Redirect::to("/inbox").into_response());
 97→    }
 98→
 99→    match capture_inbox_item(&pool, user_id.clone(), form.title).await {
100→        Ok(item) => {
101→            if htmx {
102→                let template = InboxItemTemplate {
103→                    item: InboxItemView::from(&item),
104→                };
105→                let body = template.render().map_err(InboxError::Render)?;
106→                Ok(htmx_response_with_announce(Html(body), "Captured to inbox"))
107→            } else {
108→                Ok(Redirect::to("/inbox").into_response())
109→            }
110→        }
111→        Err(CaptureInboxError::InvalidTitle(title_err)) => {
112→            let user_facing = match title_err {
113→                crate::domain::TodoTitleError::Empty => {
114→                    if htmx {
115→                        return Ok(StatusCode::NO_CONTENT.into_response());
116→                    }
117→                    return Ok(Redirect::to("/inbox").into_response());
118→                }
119→                crate::domain::TodoTitleError::TooLong { max, .. } => {
120→                    format!("That title is too long (max {max} characters)")
121→                }
122→            };
123→
124→            let items = get_inbox_items(&pool, &user_id)
125→                .await
126→                .map_err(InboxError::Unexpected)?;
127→            let inbox_count = items.len() as i64;
128→            let item_views: Vec<InboxItemView> = items.iter().map(InboxItemView::from).collect();
129→
130→            let template = InboxTemplate {
131→                current_page: "inbox",
132→                inbox_count,
133→                items: item_views,
134→            };
135→            let _ = user_facing; // Title too long error is shown via template if needed
136→            let body = template.render().map_err(InboxError::Render)?;
137→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
138→        }
139→        Err(CaptureInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
140→    }
141→}
142→
143→pub async fn post_delete_inbox_item(
144→    AuthenticatedUser(user_id): AuthenticatedUser,
145→    State(pool): State<PgPool>,
146→    headers: HeaderMap,
147→    Path(item_id): Path<Uuid>,
148→) -> Result<Response, InboxError> {
149→    let htmx = is_htmx_request(&headers);
150→    let inbox_item_id = InboxItemId::from_uuid(item_id);
151→
152→    match delete_inbox_item(&pool, &inbox_item_id, &user_id).await {
153→        Ok(()) => {
154→            if htmx {
155→                Ok(htmx_response_with_announce(
156→                    Html(String::new()),
157→                    "Inbox item deleted",
158→                ))
159→            } else {
160→                Ok(Redirect::to("/inbox").into_response())
161→            }
162→        }
163→        Err(DeleteInboxError::NotFound) => Ok((
164→            StatusCode::NOT_FOUND,
165→            Html("<h1>Inbox item not found</h1>".to_string()),
166→        )
167→            .into_response()),
168→        Err(DeleteInboxError::Unauthorized) => Ok((
169→            StatusCode::FORBIDDEN,
170→            Html("<h1>Not authorized</h1>".to_string()),
171→        )
172→            .into_response()),
173→        Err(DeleteInboxError::Unexpected(err)) => Err(InboxError::Unexpected(err)),
174→    }
175→}
176→
177→#[derive(Debug, thiserror::Error)]
178→pub enum InboxError {
179→    #[error("Failed to render template")]
180→    Render(#[from] askama::Error),
181→    #[error(transparent)]
182→    Unexpected(anyhow::Error),
183→}
184→
185→impl IntoResponse for InboxError {
186→    fn into_response(self) -> Response {
187→        tracing::error!(error = %self, "Inbox error");
188→        (
189→            StatusCode::INTERNAL_SERVER_ERROR,
190→            Html("<h1>Something went wrong</h1>".to_string()),
191→        )
192→            .into_response()
193→    }
194→}
