18→
19→pub struct Application {
20→    listener: TcpListener,
21→    pool: PgPool,
22→}
23→
24→impl Application {
25→    pub async fn build(settings: &Settings) -> Result<Self, anyhow::Error> {
26→        let pool = PgPoolOptions::new()
27→            .max_connections(5)
28→            .connect_with(settings.database.connect_options())
29→            .await?;
30→
31→        sqlx::migrate!("./migrations").run(&pool).await?;
32→
33→        let session_store = PostgresStore::new(pool.clone());
34→        session_store.migrate().await?;
35→
36→        let address = format!(
37→            "{}:{}",
38→            settings.application.host, settings.application.port
39→        );
40→        let listener = TcpListener::bind(&address).await?;
41→
42→        tracing::info!("Listening on {}", listener.local_addr()?);
43→
44→        Ok(Self { listener, pool })
45→    }
46→
47→    pub fn port(&self) -> u16 {
48→        self.listener.local_addr().unwrap().port()
49→    }
50→
51→    pub fn router(pool: PgPool) -> Router {
52→        let x_request_id = axum::http::HeaderName::from_static("x-request-id");
53→
54→        let session_store = PostgresStore::new(pool.clone());
55→        let session_layer = SessionManagerLayer::new(session_store);
56→
57→        Router::new()
58→            .route("/", axum::routing::get(index))
59→            .route("/dashboard", axum::routing::get(get_dashboard))
60→            .route("/inbox", axum::routing::get(get_inbox).post(post_inbox))
61→            .route(
62→                "/inbox/{id}/delete",
63→                axum::routing::post(post_delete_inbox_item),
64→            )
65→            .route("/next-actions", axum::routing::get(get_next_actions))
66→            .route("/projects", axum::routing::get(get_projects))
67→            .route("/waiting-for", axum::routing::get(get_waiting_for))
68→            .route("/someday-maybe", axum::routing::get(get_someday_maybe))
69→            .route("/review", axum::routing::get(get_review))
70→            .route(
71→                "/register",
72→                axum::routing::get(get_register).post(post_register),
73→            )
74→            .route("/login", axum::routing::get(get_login).post(post_login))
75→            .route("/forgot-password", axum::routing::get(get_forgot_password))
76→            .route("/logout", axum::routing::post(post_logout))
77→            .route("/todos", axum::routing::get(get_todos_page).post(post_todo))
78→            .route("/todos/{id}", axum::routing::get(get_todo_item))
79→            .route("/todos/{id}/toggle", axum::routing::post(post_toggle_todo))
80→            .route("/todos/{id}/delete", axum::routing::post(post_delete_todo))
81→            .route(
82→                "/todos/{id}/edit",
83→                axum::routing::get(get_edit_todo).post(post_edit_todo),
84→            )
85→            .route("/health_check", axum::routing::get(health_check))
86→            .nest_service("/static", ServeDir::new("static"))
87→            .layer(session_layer)
88→            .layer(TraceLayer::new_for_http())
89→            .layer(PropagateRequestIdLayer::new(x_request_id.clone()))
90→            .layer(SetRequestIdLayer::new(x_request_id, MakeRequestUuid))
91→            .with_state(pool)
92→    }
93→
